function submitTransactionWithSignatures(
    address destination,
    uint value,
    bytes data,
    uint nonce,
    uint8[] v,
    bytes32[] rs)
    external
    ownerExists(msg.sender)
    returns (bytes32 transactionHash)
{
    // ...
}
